import React from "react";

const SearchBar = ({ search, setSearch, category, setCategory, level, setLevel }) => {
  const categories = ["All", "Programming Language", "Web Development", "Backend Development", "Data Science"];
  const levels = ["All", "Beginner", "Intermediate", "Advanced"];

  const tabStyle = (active) => ({
    padding: "5px 14px",
    borderRadius: 50,
    fontSize: "0.82rem",
    fontWeight: 500,
    border: active ? "1px solid #6c63ff" : "1px solid #2a2a4a",
    background: active ? "#6c63ff" : "transparent",
    color: active ? "white" : "#9999bb",
    cursor: "pointer",
    transition: "all 0.2s",
    whiteSpace: "nowrap"
  });

  const levelActive = (active) => ({
    padding: "5px 14px",
    borderRadius: 50,
    fontSize: "0.82rem",
    fontWeight: 500,
    border: active ? "1px solid #43d9ad" : "1px solid #2a2a4a",
    background: active ? "#43d9ad" : "transparent",
    color: active ? "#0f0f1a" : "#9999bb",
    cursor: "pointer",
    transition: "all 0.2s",
    whiteSpace: "nowrap"
  });

  return (
    <div className="py-4">
      {/* Search Input */}
      <div className="row mb-4">
        <div className="col-12 col-md-6">
          <div className="input-group">
            <span className="input-group-text" style={{ background: "#1a1a2e", border: "1px solid #2a2a4a", borderRight: "none", color: "#666688" }}>
              <i className="bi bi-search"></i>
            </span>
            <input
              type="text"
              className="form-control form-control-dark"
              placeholder="Search programming courses..."
              value={search}
              onChange={e => setSearch(e.target.value)}
              style={{ background: "#1a1a2e", border: "1px solid #2a2a4a", borderLeft: "none", color: "#e8e8f0" }}
            />
            {search && (
              <button
                className="btn"
                onClick={() => setSearch("")}
                style={{ background: "#1a1a2e", border: "1px solid #2a2a4a", borderLeft: "none", color: "#666688" }}
              >
                <i className="bi bi-x"></i>
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Category Filter */}
      <div className="mb-3 d-flex align-items-center gap-3 flex-wrap">
        <span className="small fw-bold text-uppercase" style={{ color: "#666688", letterSpacing: "0.06em", minWidth: 70 }}>
          Category:
        </span>
        <div className="d-flex gap-2 flex-wrap">
          {categories.map(cat => (
            <button key={cat} style={tabStyle(category === cat)} onClick={() => setCategory(cat)}>
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* Level Filter */}
      <div className="d-flex align-items-center gap-3 flex-wrap">
        <span className="small fw-bold text-uppercase" style={{ color: "#666688", letterSpacing: "0.06em", minWidth: 70 }}>
          Level:
        </span>
        <div className="d-flex gap-2 flex-wrap">
          {levels.map(lv => (
            <button key={lv} style={levelActive(level === lv)} onClick={() => setLevel(lv)}>
              {lv}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

export default SearchBar;
